using Microsoft.AspNetCore.Mvc;using attendance_monitoring.Controllers;using attendance_monitoring.IServices;using attendance_monitoring.Classes;using Microsoft.Extensions.Logging;namespace attendance.testproject.Controllers_Testing;/// <summary>/// Test sa GetStudents endpoint/// </summary>public class StudentControllerTest{    private readonly Mock<IStudentService> _mockStudentService;    private readonly StudentController _studentController;    public StudentControllerTest()    {        _mockStudentService = new Mock<IStudentService>();        var mockLogger = new Mock<ILogger<StudentController>>();        _studentController = new StudentController(_mockStudentService.Object, mockLogger.Object);    }        [Fact]    public async Task GetStudents_ReturnsOkResult_WithStudentsList()    {        // Arrange        var expectedStudents = new List<Student>        {            new Student { Id = 1, Firstname = "John", Lastname = "Doe", Email = "john.doe@example.com" },            new Student { Id = 2, Firstname = "Jane", Lastname = "Smith", Email = "jane.smith@example.com" }        };        _mockStudentService            .Setup(s => s.GetAllNonDeletedStudentsAsync())            .ReturnsAsync(expectedStudents);        // Act        var result = await _studentController.GetStudents();        // Assert        var okResult = Assert.IsType<OkObjectResult>(result.Result);        var students = Assert.IsAssignableFrom<IList<Student>>(okResult.Value);        Assert.Equal(2, students.Count);        Assert.Equal("John", students.First().Firstname);        Assert.Equal("jane.smith@example.com", students.Last().Email);                // Verify the service was called with correct parameters        _mockStudentService.Verify(s => s.GetAllNonDeletedStudentsAsync(), Times.Once);    }}